{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT MIN(createddate), MAX(createddate) FROM \\\"Case\\\";\"",
  "description": "Case date range"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT COUNT(*) FROM \\\"Case\\\" WHERE createddate >= '2023-05-02' AND createddate < '2023-09-03';\"",
  "description": "Count cases in past 4 months"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT caseid__c, COUNT(*) FROM casehistory__c WHERE field__c='Owner Assignment' GROUP BY caseid__c HAVING COUNT(*) > 1 LIMIT 5;\"",
  "description": "Check transferred cases"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c "
WITH recent_cases AS (
  SELECT id, createddate, closeddate FROM \"Case\"
  WHERE createddate >= '2023-05-02' AND createddate < '2023-09-03'
)
SELECT COUNT(*) as total,
       COUNT(CASE WHEN closeddate IS NOT NULL AND closeddate <> '' THEN 1 END) as closed
FROM recent_cases;
"",
  "description": "Count closed cases in range"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c "
SELECT COUNT(*) as total,
       COUNT(CASE WHEN closeddate IS NOT NULL AND closeddate <> '' THEN 1 END) as closed
FROM \"Case\"
WHERE closeddate >= '2023-05-02' AND closeddate < '2023-09-03';
"",
  "description": "Count cases closed in past 4 months"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c "
WITH recent_cases AS (
  SELECT id, createddate, closeddate FROM \"Case\"
  WHERE createddate >= '2023-05-02' AND createddate < '2023-09-03'
),
owner_assign AS (
  SELECT ch.caseid__c, ch.newvalue__c AS owner, ch.createddate AS assign_time
  FROM casehistory__c ch
  JOIN recent_cases c ON ch.caseid__c = c.id
  WHERE ch.field__c = 'Owner Assignment'
),
case_owner_count AS (
  SELECT caseid__c, COUNT(*) AS oc FROM owner_assign GROUP BY caseid__c
),
agents_per_case AS (
  SELECT DISTINCT caseid__c, owner FROM owner_assign
),
cases_processed AS (
  SELECT owner, COUNT(DISTINCT caseid__c) AS cnt FROM agents_per_case GROUP BY owner
)
SELECT * FROM cases_processed ORDER BY cnt DESC;
"",
  "description": "All agents with case counts"
}
